1	type Item = { type: string; material?: string; cursed?: boolean; enchantment?: number };
2	type Damage = { itemType: string; amount: number };
3	type Incident = { cause: string; damages: Damage[] };
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Customer = { yearsWithMHPCO: number };
8	type Input = { customer: Customer; steps: Step[] };
9	
10	const PROCESSING_FEE = 5;
11	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
12	const CURSE_SURCHARGE_PERCENT = 50;
13	const HIGH_ENCHANTMENT_THRESHOLD = 5;
14	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
15	const LOYALTY_THRESHOLD_YEARS = 2;
16	const LOYALTY_DISCOUNT_PERCENT = 20;
17	const FOLLOWUP_CONTRACT_DISCOUNT_PERCENT = 15;
18	const COMPONENT_BLOCK_SIZE = 3;
19	const COMPONENT_BLOCK_PREMIUM = 60;
20	const DEDUCTIBLE = 100;
21	const CAP_MULTIPLIER = 2;
22	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
23	const HIGH_ENCHANTMENT_CLAIM_PERCENT = 50;
24	
25	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
26	  sword: 1000,
27	  amulet: 600,
28	  staff: 800,
29	  potion: 400,
30	  rune: 250,
31	  moonstone: 250,
32	};
33	
34	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
35	  sword: 100,
36	  amulet: 60,
37	  staff: 80,
38	  potion: 40,
39	  rune: 25,
40	  moonstone: 25,
41	};
42	
43	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
44	
45	const groupBaseAmount = (type: string, count: number): number => {
46	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
47	    return COMPONENT_BLOCK_PREMIUM;
48	  }
49	  return count * BASE_PREMIUM_BY_TYPE[type];
50	};
51	
52	const frequencyMap = <T>(values: T[], keyOf: (value: T) => string): Map<string, number> =>
53	  values.reduce(
54	    (counts, value) => {
55	      const key = keyOf(value);
56	      return counts.set(key, (counts.get(key) ?? 0) + 1);
57	    },
58	    new Map<string, number>(),
59	  );
60	
61	const countByType = (items: Item[]): Map<string, number> =>
62	  frequencyMap(items, (item) => item.type);
63	
64	const basePremium = (items: Item[]): number =>
65	  Array.from(countByType(items)).reduce(
66	    (total, [type, count]) => total + groupBaseAmount(type, count),
67	    0,
68	  );
69	
70	const percentOf = (amount: number, percent: number): number =>
71	  (amount * percent) / 100;
72	
73	const percentOfItemBase = (item: Item, percent: number): number =>
74	  percentOf(BASE_PREMIUM_BY_TYPE[item.type], percent);
75	
76	const firstInsuranceSurcharge = (base: number): number =>
77	  percentOf(base, FIRST_INSURANCE_SURCHARGE_PERCENT);
78	
79	const enchantmentAtLeast = (item: Item, threshold: number): boolean =>
80	  (item.enchantment ?? 0) >= threshold;
81	
82	type ItemSurchargeRule = { applies: (item: Item) => boolean; percent: number };
83	
84	const ITEM_SURCHARGE_RULES: ItemSurchargeRule[] = [
85	  { applies: (item) => item.cursed === true, percent: CURSE_SURCHARGE_PERCENT },
86	  { applies: (item) => enchantmentAtLeast(item, HIGH_ENCHANTMENT_THRESHOLD), percent: HIGH_ENCHANTMENT_SURCHARGE_PERCENT },
87	];
88	
89	const surchargesForItem = (item: Item): number =>
90	  ITEM_SURCHARGE_RULES.reduce(
91	    (sum, { applies, percent }) => sum + (applies(item) ? percentOfItemBase(item, percent) : 0),
92	    0,
93	  );
94	
95	const itemSurcharges = (items: Item[]): number =>
96	  items.reduce((sum, item) => sum + surchargesForItem(item), 0);
97	
98	type PolicyContext = { customer: Customer; stepIndex: number };
99	type PolicyDiscountRule = { applies: (ctx: PolicyContext) => boolean; percent: number };
100	
101	const POLICY_DISCOUNT_RULES: PolicyDiscountRule[] = [
102	  { applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS, percent: LOYALTY_DISCOUNT_PERCENT },
103	  { applies: ({ stepIndex }) => stepIndex > 0, percent: FOLLOWUP_CONTRACT_DISCOUNT_PERCENT },
104	];
105	
106	const policyDiscounts = (base: number, ctx: PolicyContext): number =>
107	  POLICY_DISCOUNT_RULES.reduce(
108	    (sum, { applies, percent }) => sum + (applies(ctx) ? percentOf(base, percent) : 0),
109	    0,
110	  );
111	
112	const quotePremium = (items: Item[], ctx: PolicyContext): number => {
113	  const base = basePremium(items);
114	  const surcharges = itemSurcharges(items) + firstInsuranceSurcharge(base);
115	  const discounts = policyDiscounts(base, ctx);
116	  return Math.ceil(base + surcharges - discounts + PROCESSING_FEE);
117	};
118	
119	const insuranceSum = (items: Item[]): number =>
120	  items.reduce((sum, { type }) => sum + INSURANCE_VALUE_BY_TYPE[type], 0);
121	
122	const policyCap = (items: Item[]): number => CAP_MULTIPLIER * insuranceSum(items);
123	
124	const reimbursableAmount = (amount: number, item: Item): number =>
125	  enchantmentAtLeast(item, HIGH_ENCHANTMENT_CLAIM_THRESHOLD)
126	    ? percentOf(amount, HIGH_ENCHANTMENT_CLAIM_PERCENT)
127	    : amount;
128	
129	const damagePayout = (amount: number, item: Item): number =>
130	  Math.max(0, reimbursableAmount(amount, item) - DEDUCTIBLE);
131	
132	const findInsuredItem = (items: Item[], itemType: string): Item => {
133	  const item = items.find((i) => i.type === itemType);
134	  if (!item) throw new Error(`item type ${itemType} not in policy`);
135	  return item;
136	};
137	
138	const validateDamageCounts = (damages: Damage[], items: Item[]): void => {
139	  const insuredCounts = countByType(items);
140	  const damageCounts = frequencyMap(damages, (damage) => damage.itemType);
141	  for (const [itemType, count] of damageCounts) {
142	    if (count > (insuredCounts.get(itemType) ?? 0)) {
143	      throw new Error(`more ${itemType} damages than insured`);
144	    }
145	  }
146	};
147	
148	const validateDamageAmounts = (damages: Damage[]): void => {
149	  const negative = damages.find((d) => d.amount < 0);
150	  if (negative) {
151	    throw new Error(`negative damage amount: ${negative.amount}`);
152	  }
153	};
154	
155	const totalRequestedPayout = (damages: Damage[], items: Item[]): number => {
156	  validateDamageAmounts(damages);
157	  validateDamageCounts(damages, items);
158	  return damages.reduce(
159	    (sum, { itemType, amount }) => sum + damagePayout(amount, findInsuredItem(items, itemType)),
160	    0,
161	  );
162	};
163	
164	type Policy = { items: Item[]; remainingCap: number };
165	
166	type StepResult = { premium: number } | { payout: number; remainingCap: number };
167	
168	const validateItemTypes = (items: Item[]): void => {
169	  const unknown = items.find((item) => !(item.type in BASE_PREMIUM_BY_TYPE));
170	  if (unknown) {
171	    throw new Error(`unknown item type: ${unknown.type}`);
172	  }
173	};
174	
175	const processQuote = (step: QuoteStep, ctx: PolicyContext, policies: Policy[]): StepResult => {
176	  validateItemTypes(step.items);
177	  policies.push({ items: step.items, remainingCap: policyCap(step.items) });
178	  return { premium: quotePremium(step.items, ctx) };
179	};
180	
181	const processClaim = (step: ClaimStep, policies: Policy[]): StepResult => {
182	  const policy = policies[step.policy];
183	  const requested = totalRequestedPayout(step.incident.damages, policy.items);
184	  const payout = Math.floor(Math.min(requested, policy.remainingCap));
185	  policy.remainingCap -= payout;
186	  return { payout, remainingCap: policy.remainingCap };
187	};
188	
189	export const run = (input: unknown): unknown => {
190	  const { customer, steps } = input as Input;
191	  const policies: Policy[] = [];
192	  const results = steps.map((step, stepIndex): StepResult =>
193	    step.op === "quote"
194	      ? processQuote(step, { customer, stepIndex }, policies)
195	      : processClaim(step, policies),
196	  );
197	  return { results };
198	};
